import{_ as o,o as n,c as t,a2 as d}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"0004 — World spec → zone content binding","description":"","frontmatter":{},"headers":[],"relativePath":"decisions/0004-world-spec-to-zone-binding.md","filePath":"decisions/0004-world-spec-to-zone-binding.md","lastUpdated":1782023531000}'),a={name:"decisions/0004-world-spec-to-zone-binding.md"};function s(r,e,c,i,l,h){return n(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="_0004-—-world-spec-→-zone-content-binding" tabindex="-1">0004 — World spec → zone content binding <a class="header-anchor" href="#_0004-—-world-spec-→-zone-content-binding" aria-label="Permalink to &quot;0004 — World spec → zone content binding&quot;">​</a></h1><ul><li>Status: Accepted</li><li>Date: 2026-06-21</li><li>Deciders: Daedalus (CTO), Wayland (impl)</li><li>Context issue: <a href="https://github.com/Flopsstuff/korovany" target="_blank" rel="noreferrer">FLO-411</a></li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The three world specs (<code>docs/guide/worlds/*.md</code>) describe each zone&#39;s lore, landmarks, encounter hooks, and asset needs in prose. Until now that prose bound to the running game only as <code>loreName</code> strings in <code>src/game/world/zones.ts</code>, plus <strong>hardcoded magic-number arrays inline in each scene</strong> — e.g. a <code>const LANDMARKS: [number, number, number, number, number, number][]</code> in <code>humanLandsScene.ts</code> and <code>FOREST_SOLDIER_SPAWNS</code> / <code>FOREST_CARAVAN_SPAWNS</code> in <code>forestScene.ts</code>. The specs nobody&#39;s code reads; the numbers nobody&#39;s spec explains. MPG.5 (&quot;populate the world&quot;) and every future zone build need one source of truth for <em>what is in a zone</em>.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>World specs are <strong>content briefs</strong>, not data the engine parses. They attach to the four-zone registry through a typed, engine-agnostic content layer:</p><ul><li><code>src/game/world/zoneContent.ts</code> exports <code>ZONE_CONTENT: Record&lt;ZoneId, ZoneContent&gt;</code>, where each <code>ZoneContent</code> carries: <ul><li><strong><code>landmarks</code></strong> — <code>ZoneLandmark[]</code>: <code>id</code>, design <code>role</code>, <code>{x, z}</code> position, <code>height</code>/<code>size</code>, and either a greybox <code>color</code> or an <code>assetKey</code> for a streamed GLB. Seeded from each spec&#39;s &quot;Landmark briefs&quot;.</li><li><strong><code>encounterAnchors</code></strong> — <code>EncounterAnchor[]</code>: named <code>{x, y, z}</code> spawn points tagged <code>soldier | caravan</code>, distilled from each spec&#39;s &quot;Encounter hooks&quot;.</li></ul></li><li><code>getZoneContent(zoneId)</code> is the accessor, sitting next to <code>getZone()</code> and re-exported from <code>src/game/world/index.ts</code>. It is <strong>total</strong> over the <code>ZoneId</code> union — locked zones return an empty table — so callers holding a <code>ZoneId</code> never branch on <code>undefined</code>.</li><li>The two <code>available</code> zones carry real content seeded from their specs (<code>human-lands</code> ← <code>velya-salt-road.md</code>, <code>forest</code> ← <code>lysaen-emerald-thicket.md</code>). <code>empire</code> and <code>mountains</code> stay <code>locked</code> with empty content until their scenes exist.</li><li><strong>Division of responsibility:</strong> landmark/encounter <em>data</em> lives in code (<code>zoneContent.ts</code>); <em>prose</em> (lore, mood, traversal notes, asset priorities) stays in <code>docs/guide/worlds/</code>. The two are linked by the <code>ZoneId</code> key and by ADR reference, not duplicated.</li></ul><p>Scenes consume the table by id (<code>humanLandsScene</code> renders its landmark greyboxes from <code>zoneContent</code>; both scenes derive their soldier/caravan spawns from the encounter anchors) instead of carrying inline constants.</p><h3 id="lenses" tabindex="-1">Lenses <a class="header-anchor" href="#lenses" aria-label="Permalink to &quot;Lenses&quot;">​</a></h3><ul><li><strong>Schema is forever.</strong> <code>ZoneContent</code> is keyed by <code>ZoneId</code>, and <code>ZoneId</code>s are persisted in saves (<code>playerSlice.zoneId</code>). The keys are forever — never rename a zone id without a save migration. Landmark/anchor <code>id</code>s are likewise stable identifiers, not display strings.</li><li><strong>Trust the boundary.</strong> The content table&#39;s shape is validated <strong>once</strong> in <code>zoneContent.test.ts</code> (every available zone has ≥1 landmark; every landmark and anchor type-checks and carries the required fields). Scenes downstream of that boundary trust the table and do not re-validate it.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li>MPG.5 and future zone builds read one source of truth; adding a landmark or encounter is a data edit in <code>zoneContent.ts</code>, not a scene-code change.</li><li><code>humanLandsScene</code>&#39;s inline <code>LANDMARKS</code> const and both scenes&#39; inline spawn arrays are gone; the human-lands greybox still renders identically (the table is seeded from the exact prior numbers — guarded by a pure-extraction test).</li><li>Landmarks can migrate from greybox <code>color</code> to streamed <code>assetKey</code> without touching scene code — the scene already reads geometry + appearance from data.</li><li>The forest scene streams its environment via GLB assets rather than greybox boxes, so its landmark data is currently consumed only by tests and MPG.5, not rendered as boxes — intentional; the data still exists as the populate-pass source of truth.</li></ul>',12)])])}const p=o(a,[["render",s]]);export{m as __pageData,p as default};
